export function createUserCache(storage) {
  if (!storage || typeof storage.loadUser !== "function" || typeof storage.saveUser !== "function") {
    throw new TypeError("storage must provide loadUser and saveUser");
  }

  const cachedUsers = new Map();

  return {
    getUser(id) {
      if (cachedUsers.has(id)) {
        return cachedUsers.get(id);
      }
      const loaded = storage.loadUser(id);
      if (loaded) {
        cachedUsers.set(id, loaded);
      }
      return loaded;
    },
    updateUser(id, user) {
      const saved = storage.saveUser(id, user);
      cachedUsers.set(id, saved);
      return saved;
    },
    clear() {
      cachedUsers.clear();
    }
  };
}

import test from "node:test";
import assert from "node:assert/strict";

import { createUserCache } from "../src/cache.js";
import { createMemoryUserStorage } from "../src/cache-storage.js";

test("returns a cached user on repeated reads", () => {
  const storage = createMemoryUserStorage({
    "user-1": { name: "Ada" }
  });
  const cache = createUserCache(storage);

  assert.deepEqual(cache.getUser("user-1"), { name: "Ada" });
  assert.deepEqual(cache.getUser("user-1"), { name: "Ada" });
  assert.deepEqual(storage.calls.loadUser, ["user-1"]);
});

test("returns null on a cache miss and records the storage lookup", () => {
  const storage = createMemoryUserStorage();
  const cache = createUserCache(storage);

  assert.equal(cache.getUser("missing-user"), null);
  assert.deepEqual(storage.calls.loadUser, ["missing-user"]);
});

test("returns the updated user instead of stale cached data", () => {
  const storage = createMemoryUserStorage({
    "user-1": { name: "Ada", role: "reader" }
  });
  const cache = createUserCache(storage);

  assert.deepEqual(cache.getUser("user-1"), { name: "Ada", role: "reader" });

  const replacement = cache.updateUser("user-1", { name: "Ada", role: "admin" });

  assert.deepEqual(replacement, { name: "Ada", role: "admin" });
  assert.deepEqual(cache.getUser("user-1"), { name: "Ada", role: "admin" });
  assert.deepEqual(storage.calls.loadUser, ["user-1"]);
  assert.deepEqual(storage.calls.saveUser, [
    { id: "user-1", user: { name: "Ada", role: "admin" } }
  ]);
});

export function createMemoryUserStorage(initialUsers = {}) {
  const users = new Map(Object.entries(initialUsers));
  const calls = {
    loadUser: [],
    saveUser: []
  };

  return {
    calls,
    loadUser(id) {
      calls.loadUser.push(id);
      return users.has(id) ? { ...users.get(id) } : null;
    },
    saveUser(id, user) {
      calls.saveUser.push({ id, user: { ...user } });
      users.set(id, { ...user });
      return { ...users.get(id) };
    }
  };
}
